DELETE FROM SRBA_ETC_I
WHERE BAS_YYMM = #{basYymm}
AND   RSK_ELMT_C LIKE 'R5%'

mapper.insert:
INSERT INTO KRBA_EXPS_EXTR_M ( BAS_YYYY,VALT_TRN,BRNO,RSK_INDCT,INDV_CORP_CCD,SRVC_G_C,RSK_CATG,RSK_EVT,RSK_LVL_C,JIPYO_V,DR_DT,DR_TIME ) SELECT /*입출금 현금 거래*/ A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C ,NVL(SUM(DL_AMT), 0) AS AMT ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS') FROM ( SELECT M.BAS_YYYY ,M.RSK_INDCT ,RSK_CATG ,RSK_FAC ,RSK_EVT ,RSK_LVL_C ,RSK_INDCT_NO ,SRVC_G_C ,RSK_INDCT_NM FROM KRBA_RSK_INDCT_M M, KRBA_RSK_INDICT_D A WHERE 1=1 AND M.BAS_YYYY = A.BAS_YYYY AND M.RSK_INDCT = A.RSK_INDCT AND USYN = 1 AND M.BAS_YYYY = #{basYymm} AND M.RSK_CATG = '3' AND RSK_FAC = '04' AND RSK_EVT = '01' ) M ,( SELECT /*+ FULL(M) PARALLEL(4) */ #{basYymm} BAS_YYYY ,#{valtTrn} VALT_TRN ,VALT_BRNO ,SRVC_G_C ,M.RNMCNO ,NVL((SELECT INDV_CORP_CCD FROM KRBA_CUST_I WHERE BAS_YYYY = #{basYymm} AND VALT_TRN = #{valtTrn} AND RNMCNO = M.RNMCNO ),1) INDV_CORP_CCD ,SUM(DL_AMT) DL_AMT FROM KRBA_TRN_I M WHERE 1=1 AND M.DL_TYP_CD IN ('01' ,'02') AND M.DL_WY_CD = '01' AND M.DL_DT >= #{tgtTrnSdt} AND M.DL_DT < #{tgtTrnEdt} AND M.BNCC_TRN_YN = 'N' GROUP BY VALT_BRNO ,SRVC_G_C ,M.RNMCNO
) A WHERE 1=1 AND M.SRVC_G_C = A.SRVC_G_C GROUP BY A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C UNION ALL SELECT /*입출금 -개인법인간 이체거래*/ A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C ,NVL(SUM(DL_AMT), 0) AS AMT ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS') FROM ( SELECT M.BAS_YYYY ,M.RSK_INDCT ,RSK_CATG ,RSK_FAC ,RSK_EVT ,RSK_LVL_C ,RSK_INDCT_NO ,SRVC_G_C ,RSK_INDCT_NM FROM KRBA_RSK_INDCT_M M, KRBA_RSK_INDICT_D A WHERE 1=1 AND M.BAS_YYYY = A.BAS_YYYY AND M.RSK_INDCT = A.RSK_INDCT AND USYN = 1 AND M.BAS_YYYY = #{basYymm} AND M.RSK_CATG = '3' AND RSK_FAC = '04' AND RSK_EVT = '02' ) M ,( SELECT /*+ FULL(M) PARALLEL(4) */ #{basYymm} BAS_YYYY ,#{valtTrn} VALT_TRN ,VALT_BRNO ,SRVC_G_C ,M.RNMCNO ,NVL((SELECT INDV_CORP_CCD FROM KRBA_CUST_I WHERE BAS_YYYY = #{basYymm} AND VALT_TRN = #{valtTrn} AND RNMCNO = M.RNMCNO ),1) INDV_CORP_CCD ,SUM(DL_AMT) DL_AMT FROM KRBA_TRN_I M WHERE 1=1 AND M.DL_DT >= #{tgtTrnSdt} AND M.DL_DT < #{tgtTrnEdt} AND M.DL_TYP_CD IN ('01' ,'02') AND M.PECO_TRN_CD IN ('2','3') AND M.BNCC_TRN_YN = 'N' GROUP BY VALT_BRNO ,SRVC_G_C ,M.RNMCNO
) A WHERE 1=1 AND M.SRVC_G_C = A.SRVC_G_C GROUP BY A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C UNION ALL SELECT /*입출금-고액거래*/ A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C ,NVL(SUM(DL_AMT), 0) AMT ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS') FROM ( SELECT M.BAS_YYYY ,M.RSK_INDCT ,RSK_CATG ,RSK_FAC ,RSK_EVT ,RSK_LVL_C ,RSK_INDCT_NO ,SRVC_G_C ,RSK_INDCT_NM FROM KRBA_RSK_INDCT_M M, KRBA_RSK_INDICT_D A WHERE 1=1 AND M.BAS_YYYY = A.BAS_YYYY AND M.RSK_INDCT = A.RSK_INDCT AND USYN = 1 AND M.BAS_YYYY = #{basYymm} AND M.RSK_CATG = '3' AND RSK_FAC = '04' AND RSK_EVT = '03' ) M ,( SELECT BAS_YYYY ,VALT_TRN ,VALT_BRNO ,SRVC_G_C ,NVL((SELECT INDV_CORP_CCD FROM NIC01B WHERE RNMCNO = M.RNMCNO ),1) INDV_CORP_CCD ,SUM(DL_AMT) DL_AMT FROM ( SELECT #{basYymm} BAS_YYYY ,#{valtTrn} VALT_TRN ,(CASE WHEN PRFT_BRN_CD = '21320' THEN MNGG_BRN_CD ELSE NVL(PRFT_BRN_CD,MNGG_BRN_CD) END) VALT_BRNO ,(CASE WHEN ACNT_TYPE_CLSN_CODE = 'P01' THEN '01' WHEN ACNT_TYPE_CLSN_CODE = 'P02' THEN '02' WHEN ACNT_TYPE_CLSN_CODE = 'P03' THEN '03' WHEN ACNT_TYPE_CLSN_CODE = 'P04' THEN '04' WHEN ACNT_TYPE_CLSN_CODE = 'P05' THEN '05' WHEN ACNT_TYPE_CLSN_CODE = 'P06' THEN '06' WHEN ACNT_TYPE_CLSN_CODE = 'P07' THEN '07' WHEN ACNT_TYPE_CLSN_CODE = 'P08' THEN '08' WHEN ACNT_TYPE_CLSN_CODE = 'P09' THEN '09' WHEN ACNT_TYPE_CLSN_CODE = 'P10' THEN '10' WHEN PRDT_CLSN_CODE = 'A' THEN '11' WHEN PRDT_CLSN_CODE = 'B' THEN '12' WHEN PRDT_CLSN_CODE = 'C' THEN '13' WHEN PRDT_CLSN_CODE = 'D' THEN '14' WHEN PRDT_CLSN_CODE = 'E' THEN '15' WHEN PRDT_CLSN_CODE = 'F' THEN '16' WHEN PRDT_CLSN_CODE = 'G' THEN '17' WHEN PRDT_CLSN_CODE = 'I' THEN '18' WHEN PRDT_CLSN_CODE = 'K' THEN '19' WHEN PRDT_CLSN_CODE = 'M' THEN '20' WHEN PRDT_CLSN_CODE = 'O' THEN '21' -- 일반상품 WHEN SERV_CLSN_CODE = 'S01' THEN '22' -- 계좌입출금 WHEN SERV_CLSN_CODE = 'S02' THEN '23' -- 신용 WHEN SERV_CLSN_CODE = 'S03' THEN '24' -- IB금융 WHEN SERV_CLSN_CODE = 'S04' THEN '25' -- 인수및중개 ELSE '' END ) SRVC_G_C ,M.RNMCNO ,DL_AMT FROM NIC75B M WHERE 1=1 AND M.DL_DT >= #{tgtTrnSdt} AND M.DL_DT < #{tgtTrnEdt} AND SUBSTR(SSPS_DL_ID,4,4) IN ('WLA1' ,'WLA2') -- 고액 입금,출금
) M GROUP BY BAS_YYYY ,VALT_TRN ,VALT_BRNO, RNMCNO ,SRVC_G_C ) A WHERE 1=1 AND M.SRVC_G_C = A.SRVC_G_C GROUP BY A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C
UNION ALL
SELECT /*입출금-다수계좌보유거래*/ A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C ,NVL(SUM(DL_AMT), 0) AS AMT ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS') FROM ( SELECT M.BAS_YYYY ,M.RSK_INDCT ,RSK_CATG ,RSK_FAC ,RSK_EVT ,RSK_LVL_C ,RSK_INDCT_NO ,SRVC_G_C ,RSK_INDCT_NM FROM KRBA_RSK_INDCT_M M, KRBA_RSK_INDICT_D A WHERE 1=1 AND M.BAS_YYYY = A.BAS_YYYY AND M.RSK_INDCT = A.RSK_INDCT AND USYN = 1 AND M.BAS_YYYY = #{basYymm} AND M.RSK_CATG = '3' AND RSK_FAC = '04' AND RSK_EVT = '04' ) M ,( SELECT BAS_YYYY ,VALT_TRN ,VALT_BRNO ,SRVC_G_C ,RNMCNO ,NVL((SELECT INDV_CORP_CCD FROM NIC01B WHERE RNMCNO = M.RNMCNO ),1) INDV_CORP_CCD ,SUM(DL_AMT) DL_AMT FROM ( SELECT #{basYymm} BAS_YYYY ,#{valtTrn} VALT_TRN ,(CASE WHEN PRFT_BRN_CD = '21320' THEN MNGG_BRN_CD ELSE NVL(PRFT_BRN_CD,MNGG_BRN_CD) END) VALT_BRNO ,(CASE WHEN ACNT_TYPE_CLSN_CODE = 'P01' THEN '01' WHEN ACNT_TYPE_CLSN_CODE = 'P02' THEN '02' WHEN ACNT_TYPE_CLSN_CODE = 'P03' THEN '03' WHEN ACNT_TYPE_CLSN_CODE = 'P04' THEN '04' WHEN ACNT_TYPE_CLSN_CODE = 'P05' THEN '05' WHEN ACNT_TYPE_CLSN_CODE = 'P06' THEN '06' WHEN ACNT_TYPE_CLSN_CODE = 'P07' THEN '07' WHEN ACNT_TYPE_CLSN_CODE = 'P08' THEN '08' WHEN ACNT_TYPE_CLSN_CODE = 'P09' THEN '09' WHEN ACNT_TYPE_CLSN_CODE = 'P10' THEN '10' WHEN PRDT_CLSN_CODE = 'A' THEN '11' -- 주식 WHEN PRDT_CLSN_CODE = 'B' THEN '12' -- 선물 WHEN PRDT_CLSN_CODE = 'C' THEN '13' -- 옵션 WHEN PRDT_CLSN_CODE = 'D' THEN '14' -- 채권 WHEN PRDT_CLSN_CODE = 'E' THEN '15' -- 파생결합증권 WHEN PRDT_CLSN_CODE = 'F' THEN '16' -- 파생계약상품 WHEN PRDT_CLSN_CODE = 'G' THEN '17' -- 펀드 WHEN PRDT_CLSN_CODE = 'I' THEN '18' -- 신탁 WHEN PRDT_CLSN_CODE = 'K' THEN '19' -- 방카 WHEN PRDT_CLSN_CODE = 'M' THEN '20' -- 단기상품 WHEN PRDT_CLSN_CODE = 'O' THEN '21' -- 일반상품 WHEN SERV_CLSN_CODE = 'S01' THEN '22' -- 계좌입출금 WHEN SERV_CLSN_CODE = 'S02' THEN '23' -- 신용 WHEN SERV_CLSN_CODE = 'S03' THEN '24' -- IB금융 WHEN SERV_CLSN_CODE = 'S04' THEN '25' -- 인수및중개 ELSE '' END ) SRVC_G_C ,M.RNMCNO ,DL_AMT FROM NIC75B M WHERE 1=1 AND M.DL_DT >= #{tgtTrnSdt} AND M.DL_DT < #{tgtTrnEdt} AND SUBSTR(SSPS_DL_ID,4,4) IN ('CBN1' ,'CBN2')
) M GROUP BY BAS_YYYY ,VALT_TRN ,VALT_BRNO,RNMCNO ,SRVC_G_C ) A WHERE 1=1 AND M.SRVC_G_C = A.SRVC_G_C GROUP BY A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C UNION ALL
SELECT /*입출금-분할입금거래*/ A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C ,NVL(SUM(DL_AMT), 0) AS AMT ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS') FROM ( SELECT M.BAS_YYYY ,M.RSK_INDCT ,RSK_CATG ,RSK_FAC ,RSK_EVT ,RSK_LVL_C ,RSK_INDCT_NO ,SRVC_G_C ,RSK_INDCT_NM FROM KRBA_RSK_INDCT_M M, KRBA_RSK_INDICT_D A WHERE 1=1 AND M.BAS_YYYY = A.BAS_YYYY AND M.RSK_INDCT = A.RSK_INDCT AND USYN = 1 AND M.BAS_YYYY = #{basYymm} AND M.RSK_CATG = '3' AND RSK_FAC = '04' AND RSK_EVT = '05' ) M ,( SELECT BAS_YYYY ,VALT_TRN ,VALT_BRNO ,SRVC_G_C ,RNMCNO ,NVL((SELECT INDV_CORP_CCD FROM NIC01B WHERE RNMCNO = M.RNMCNO ),1) INDV_CORP_CCD ,SUM(DL_AMT) DL_AMT FROM ( SELECT #{basYymm} BAS_YYYY ,#{valtTrn} VALT_TRN ,(CASE WHEN PRFT_BRN_CD = '21320' THEN MNGG_BRN_CD ELSE NVL(PRFT_BRN_CD,MNGG_BRN_CD) END) VALT_BRNO ,(CASE WHEN ACNT_TYPE_CLSN_CODE = 'P01' THEN '01' WHEN ACNT_TYPE_CLSN_CODE = 'P02' THEN '02' WHEN ACNT_TYPE_CLSN_CODE = 'P03' THEN '03' WHEN ACNT_TYPE_CLSN_CODE = 'P04' THEN '04' WHEN ACNT_TYPE_CLSN_CODE = 'P05' THEN '05' WHEN ACNT_TYPE_CLSN_CODE = 'P06' THEN '06' WHEN ACNT_TYPE_CLSN_CODE = 'P07' THEN '07' WHEN ACNT_TYPE_CLSN_CODE = 'P08' THEN '08' WHEN ACNT_TYPE_CLSN_CODE = 'P09' THEN '09' WHEN ACNT_TYPE_CLSN_CODE = 'P10' THEN '10' WHEN PRDT_CLSN_CODE = 'A' THEN '11' -- 주식 WHEN PRDT_CLSN_CODE = 'B' THEN '12' -- 선물 WHEN PRDT_CLSN_CODE = 'C' THEN '13' -- 옵션 WHEN PRDT_CLSN_CODE = 'D' THEN '14' -- 채권 WHEN PRDT_CLSN_CODE = 'E' THEN '15' -- 파생결합증권 WHEN PRDT_CLSN_CODE = 'F' THEN '16' -- 파생계약상품 WHEN PRDT_CLSN_CODE = 'G' THEN '17' -- 펀드 WHEN PRDT_CLSN_CODE = 'I' THEN '18' -- 신탁 WHEN PRDT_CLSN_CODE = 'K' THEN '19' -- 방카 WHEN PRDT_CLSN_CODE = 'M' THEN '20' -- 단기상품 WHEN PRDT_CLSN_CODE = 'O' THEN '21' -- 일반상품 WHEN SERV_CLSN_CODE = 'S01' THEN '22' -- 계좌입출금 WHEN SERV_CLSN_CODE = 'S02' THEN '23' -- 신용 WHEN SERV_CLSN_CODE = 'S03' THEN '24' -- IB금융 WHEN SERV_CLSN_CODE = 'S04' THEN '25' -- 인수및중개 ELSE '' END ) SRVC_G_C ,M.RNMCNO ,DL_AMT FROM NIC75B M WHERE 1=1 AND M.DL_DT >= #{tgtTrnSdt} AND M.DL_DT < #{tgtTrnEdt} AND SUBSTR(SSPS_DL_ID,4,4) = 'WCS1'
) M GROUP BY BAS_YYYY ,VALT_TRN ,VALT_BRNO,RNMCNO ,SRVC_G_C ) A WHERE 1=1 AND M.SRVC_G_C = A.SRVC_G_C GROUP BY A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C UNION ALL
SELECT /*입출금-분할출금거래*/ A.BAS_YYYY ,A.VALT_TRN ,VALT_BRNO ,RSK_INDCT ,INDV_CORP_CCD ,M.SRVC_G_C ,RSK_CATG ,RSK_EVT ,RSK_LVL_C ,NVL(SUM(DL_AMT), 0) AS AMT ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS') FROM ( SELECT M.BAS_YYYY ,M.RSK_INDCT ,RSK_CATG ,RSK_FAC ,RSK_EVT ,RSK_LVL_C ,RSK_INDCT_NO ,SRVC_G_C ,RSK_INDCT_NM FROM KRBA_RSK_INDCT_M M, KRBA_RSK_INDICT_D A WHERE 1=1 AND M.BAS_YYYY = A.BAS_YYYY AND M.RSK_INDCT = A.RSK_INDCT AND USYN = 1 AND M.BAS_YYYY = #{basYymm} AND M.RSK_CATG = '3' AND RSK_FAC = '04' AND RSK_EVT = '06' ) M ,( SELECT BAS_YYYY ,VALT_TRN ,VALT_BRNO ,SRVC_G_C ,RNMCNO ,NVL((SELECT INDV_CORP_CCD FROM NIC01B WHERE RNMCNO = M.RNMCNO ),1) INDV_CORP_CCD ,SUM(DL_AMT) DL_AMT FROM ( SELECT #{basYymm} BAS_YYYY ,#{valtTrn} VALT_TRN ,(CASE WHEN PRFT_BRN_CD = '21320' THEN MNGG_BRN_CD ELSE NVL(PRFT_BRN_CD,MNGG_BRN_CD) END) VALT_BRNO ,(CASE WHEN ACNT_TYPE_CLSN_CODE = 'P01' THEN '01' WHEN ACNT_TYPE_CLSN_CODE = 'P02' THEN '02' WHEN ACNT_TYPE_CLSN_CODE = 'P03' THEN '03' WHEN ACNT_TYPE_CLSN_CODE = 'P04' THEN '04' WHEN ACNT_TYPE_CLSN_CODE = 'P05' THEN '05' WHEN ACNT_TYPE_CLSN_CODE = 'P06' THEN '06' WHEN ACNT_TYPE_CLSN_CODE = 'P07' THEN '07' WHEN ACNT_TYPE_CLSN_CODE = 'P08' THEN '08' WHEN ACNT_TYPE_CLSN_CODE = 'P09' THEN '09' WHEN ACNT_TYPE_CLSN_CODE = 'P10' THEN '10' WHEN PRDT_CLSN_CODE = 'A' THEN '11' -- 주식 WHEN PRDT_CLSN_CODE = 'B' THEN '12' -- 선물 WHEN PRDT_CLSN_CODE = 'C' THEN '13' -- 옵션 WHEN PRDT_CLSN_CODE = 'D' THEN '14' -- 채권 WHEN PRDT_CLSN_CODE = 'E' THEN '15' -- 파생결합증권 WHEN PRDT_CLSN_CODE = 'F' THEN '16' -- 파생계약상품 WHEN PRDT_CLSN_CODE = 'G' THEN '17' -- 펀드 WHEN PRDT_CLSN_CODE = 'I' THEN '18' -- 신탁 WHEN PRDT_CLSN_CODE = 'K' THEN '19' -- 방카 WHEN PRDT_CLSN_CODE = 'M' THEN '20' -- 단기상품 WHEN PRDT_CLSN_CODE = 'O' THEN '21' -- 일반상품 WHEN SERV_CLSN_CODE = 'S01' THEN '22' -- 계좌입출금 WHEN SERV_CLSN_CODE = 'S02' THEN '23' -- 신용 WHEN SERV_CLSN_CODE = 'S03' THEN '24' -- IB금융 WHEN SERV_CLSN_CODE = 'S04' THEN '25' -- 인수및중개 ELSE '' END ) SRVC_G_C ,M.RNMCNO ,DL_AMT FROM NIC75B M WHERE 1=1 AND M.DL_DT >= #{tgtTrnSdt} AND M.DL_DT < #{tgtTrnEdt} AND SUBSTR(SSPS_DL_ID,4,4) = 'WCS2'
